1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = {
13	  type: string;
14	  material?: string;
15	  enchantment?: number;
16	  cursed?: boolean;
17	};
18	type Step = { op: "quote"; items: Item[] };
19	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
20	
21	const itemPremium = (item: Item): number => {
22	  const basePremium = BASE_PREMIUM_BY_TYPE[item.type];
23	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
24	  return basePremium + firstInsuranceSurcharge;
25	};
26	
27	const quotePremium = (items: Item[]): number => {
28	  const itemsTotal = items.reduce((sum, item) => sum + itemPremium(item), 0);
29	  return itemsTotal + PROCESSING_FEE;
30	};
31	
32	type QuoteResult = { premium: number };
33	
34	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
35	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
36	  return { results };
37	};
